import { NextResponse } from "next/server";
import { z } from "zod";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

const schema = z.object({
  cardId: z.string().cuid(),
  toListId: z.string().cuid(),
  toOrder: z.number().int().min(0),
});

export async function PATCH(req: Request) {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const parsed = schema.safeParse(await req.json());
  if (!parsed.success) return NextResponse.json({ error: "Invalid body" }, { status: 400 });

  const card = await prisma.card.findUnique({
    where: { id: parsed.data.cardId },
    include: { list: true },
  });
  if (!card) return NextResponse.json({ error: "Card not found" }, { status: 404 });

  const toList = await prisma.list.findUnique({ where: { id: parsed.data.toListId } });
  if (!toList) return NextResponse.json({ error: "Destination list not found" }, { status: 404 });

  if (card.list.boardId !== toList.boardId) {
    return NextResponse.json({ error: "Cross-board move forbidden" }, { status: 400 });
  }

  const membership = await prisma.membership.findUnique({
    where: { userId_boardId: { userId: session.user.id, boardId: toList.boardId } },
  });
  if (!membership) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  await prisma.$transaction(async (tx) => {
    await tx.card.updateMany({
      where: { listId: toList.id, order: { gte: parsed.data.toOrder } },
      data: { order: { increment: 1 } },
    });

    if (card.listId !== toList.id) {
      await tx.card.updateMany({
        where: { listId: card.listId, order: { gt: card.order } },
        data: { order: { decrement: 1 } },
      });
    }

    await tx.card.update({
      where: { id: card.id },
      data: { listId: toList.id, order: parsed.data.toOrder },
    });
  });

  return NextResponse.json({ ok: true });
}
