        <input name="password" type="password" required placeholder="Mot de passe" className="w-full p-2 rounded bg-zinc-800" />
        {error && <p className="text-red-400 text-sm">{error}</p>}
        <button disabled={loading} className="w-full bg-blue-600 hover:bg-blue-500 rounded p-2 disabled:opacity-50">
          {loading ? "Création..." : "Créer le compte"}
        </button>
      </form>
    </main>
  );
}
