import { NextResponse } from "next/server";
import { z } from "zod";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

const moveSchema = z.object({
  cardId: z.string().cuid(),
  toListId: z.string().cuid(),
  toOrder: z.number().int().min(0),
});

export async function PATCH(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const parsed = moveSchema.safeParse(await req.json());
  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid body" }, { status: 400 });
  }

  const card = await prisma.card.findUnique({
    where: { id: parsed.data.cardId },
    include: { list: true },
  });

  if (!card) return NextResponse.json({ error: "Card not found" }, { status: 404 });

  const destination = await prisma.list.findUnique({
    where: { id: parsed.data.toListId },
  });

  if (!destination) {
    return NextResponse.json({ error: "Destination list not found" }, { status: 404 });
  }

  if (card.list.boardId !== destination.boardId) {
    return NextResponse.json({ error: "Cross-board move forbidden" }, { status: 400 });
  }

  const membership = await prisma.membership.findUnique({
    where: {
      userId_boardId: {
        userId: session.user.id,
        boardId: destination.boardId,
      },
    },
  });

  if (!membership) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  await prisma.$transaction(async (tx) => {
    if (card.listId === destination.id && parsed.data.toOrder > card.order) {
      await tx.card.updateMany({
        where: {
          listId: destination.id,
          order: { gt: card.order, lte: parsed.data.toOrder },
        },
        data: { order: { decrement: 1 } },
      });
    } else {
      await tx.card.updateMany({
        where: {
          listId: destination.id,
          order: { gte: parsed.data.toOrder },
        },
        data: { order: { increment: 1 } },
      });

      await tx.card.updateMany({
        where: {
          listId: card.listId,
          order: { gt: card.order },
        },
        data: { order: { decrement: 1 } },
      });
    }

    await tx.card.update({
      where: { id: card.id },
      data: {
        listId: destination.id,
        order: parsed.data.toOrder,
      },
    });
  });

  return NextResponse.json({ ok: true });
}
