import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { AddListForm } from "./ui/add-list-form";
import { AddCardForm } from "./ui/add-card-form";

type Props = {
  params: Promise<{ boardId: string }>;
};

export default async function BoardPage({ params }: Props) {
  const session = await auth();
  if (!session?.user?.id) redirect("/login");

  const { boardId } = await params;

  const membership = await prisma.membership.findUnique({
    where: {
      userId_boardId: {
        userId: session.user.id,
        boardId,
      },
    },
  });

  if (!membership) notFound();

  const board = await prisma.board.findUnique({
    where: { id: boardId },
    include: {
      lists: {
        orderBy: { order: "asc" },
        include: {
          cards: {
            orderBy: { order: "asc" },
          },
        },
      },
    },
  });

  if (!board) notFound();

  return (
    <main className="min-h-screen bg-zinc-950 p-6 text-zinc-100">
      <div className="space-y-6">
        <h1 className="text-3xl font-bold">{board.title}</h1>
        <AddListForm boardId={board.id} />

        <div className="grid gap-4 md:grid-cols-3">
          {board.lists.map((list) => (
            <section key={list.id} className="space-y-3 rounded-xl border border-zinc-800 bg-zinc-900 p-3">
              <h2 className="font-semibold">{list.title}</h2>

              <div className="space-y-2">
                {list.cards.map((card) => (
                  <article key={card.id} className="rounded bg-zinc-800 p-2 text-sm">
                    <p className="font-medium">{card.title}</p>
                    {card.description ? <p className="mt-1 text-zinc-400">{card.description}</p> : null}
                  </article>
                ))}
              </div>

              <AddCardForm listId={list.id} />
            </section>
          ))}
        </div>
      </div>
    </main>
  );
}
